dropdownOptions={}
colNames=value['primaryIdentifierCols']
for col in colNames:
	query=system.db.execQuery(path="SetupQueries/queryUniqueItems", parameters={"tableName": value['table'], "columnName":col}, project=system.util.getProjectName())
	uniqueOptions=[]
	for row in range(query.getRowCount()):
		val=query.getValueAt(row, 0)
		uniqueOptions.append(val)
	dropdownOptions[col]=uniqueOptions
return dropdownOptions
